        deleteTokenFromKeychain()
    }
    
    func login(email: String, password: String, completion: @escaping (Result<AuthResponse, NetworkError>) -> Void) {
        let endpoint = "/auth/login"
        let authRequest = AuthRequest(email: email, password: password)
        
        post(endpoint: endpoint, body: authRequest) { (result: Result<AuthResponse, NetworkError>) in
            switch result {
            case .success(let authResponse):
                self.setAuthToken(authResponse.token)
                completion(.success(authResponse))
            case .failure(let error):
                completion(.failure(error))
            }
        }
    }
    
    func fetchUserProfile(userId: String, completion: @escaping (Result<User, NetworkError>) -> Void) {
        let endpoint = "/users/\(userId)"
        get(endpoint: endpoint, completion: completion)
    }
    
    func updateUserProfile(userId: String, user: User, completion: @escaping (Result<User, NetworkError>) -> Void) {
        let endpoint = "/users/\(userId)"
        post(endpoint: endpoint, body: user, completion: completion)
    }
    
    private func get<T: Decodable>(endpoint: String, completion: @escaping (Result<T, NetworkError>) -> Void) {
        guard let url = URL(string: environment.baseURL + endpoint) else {
            completion(.failure(.invalidURL))
            return
        }
        
        var request = URLRequest(url: url)
        request.httpMethod = "GET"
        addHeaders(to: &request)
        
        executeRequest(request: request, completion: completion)
    }
    
    private func post<T: Encodable, U: Decodable>(endpoint: String, body: T, completion: @escaping (Result<U, NetworkError>) -> Void) {
        guard let url = URL(string: environment.baseURL + endpoint) else {
            completion(.failure(.invalidURL))
            return
        }
        
        var request = URLRequest(url: url)
        request.httpMethod = "POST"
        addHeaders(to: &request)
        
        do {
            request.httpBody = try JSONEncoder().encode(body)
        } catch {
            completion(.failure(.decodingError))
            return
        }
        
        executeRequest(request: request, completion: completion)
    }
    
    private func addHeaders(to request: inout URLRequest) {
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        request.setValue("application/json", forHTTPHeaderField: "Accept")
        
        if let token = authToken {
            request.setValue("Bearer \(token)", forHTTPHeaderField: "Authorization")
        }
    }
    
    private func executeRequest<T: Decodable>(request: URLRequest, completion: @escaping (Result<T, NetworkError>) -> Void) {
        let task = session.dataTask(with: request) { data, response, error in
            if let _ = error {
                DispatchQueue.main.async {
                    completion(.failure(.unknown))
                }
                return
            }
            
            guard let httpResponse = response as? HTTPURLResponse else {
                DispatchQueue.main.async {
                    completion(.failure(.unknown))
                }
                return
            }
            
            guard (200...299).contains(httpResponse.statusCode) else {
                DispatchQueue.main.async {
                    if httpResponse.statusCode == 401 {
                        completion(.failure(.unauthorized))
                    } else {
                        completion(.failure(.serverError(httpResponse.statusCode)))
                    }
                }
                return
            }
            
            guard let data = data else {
                DispatchQueue.main.async {
                    completion(.failure(.noData))
                }
                return
            }
            
            do {
                let decodedData = try JSONDecoder().decode(T.self, from: data)
                DispatchQueue.main.async {
                    completion(.success(decodedData))
                }
            } catch {
                DispatchQueue.main.async {
                    completion(.failure(.decodingError))
                }
            }
        }
        
        task.resume()
    }
    
    private func saveTokenToKeychain(_ token: String) {
        let tokenData = token.data(using: .utf8)!
        
